#[cfg(test)]
mod tests {
    use super::*;
    use tracing_test::traced_test;

    #[traced_test]
    #[test]
    fn test_push_appends_to_end() {
        let mut log = LogViewer::new(100);
        log.push("line 1");
        log.push("line 2");
        assert_eq!(log.line_count(), 2);
        assert!(logs_contain("Pushing log line"));
    }

    #[traced_test]
    #[test]
    fn test_circular_buffer_eviction() {
        let mut log = LogViewer::new(3);
        log.push("line 1");
        log.push("line 2");
        log.push("line 3");
        log.push("line 4");  // Should evict "line 1"
        assert_eq!(log.line_count(), 3);
        assert!(logs_contain("Evicted oldest line"));
    }

    #[test]
    fn test_auto_scroll_stays_at_bottom() {
        let mut log = LogViewer::new(100);
        log.push("line 1");
        assert!(log.is_at_bottom());
        log.push("line 2");
        assert!(log.is_at_bottom());
    }

    #[test]
    fn test_manual_scroll_disables_auto_scroll() {
        let mut log = LogViewer::new(100);
        for i in 0..50 { log.push(format!("line {}", i)); }
        log.scroll_up(10);
        assert!(!log.is_at_bottom());
        log.push("new line");
        assert!(!log.is_at_bottom()); // Still scrolled up
    }

    #[test]
    fn test_scroll_to_bottom_reengages_auto_scroll() {
        let mut log = LogViewer::new(100);
        for i in 0..50 { log.push(format!("line {}", i)); }
        log.scroll_up(10);
        log.scroll_to_bottom();
        assert!(log.is_at_bottom());
    }

    #[test]
    fn test_wide_character_handling() {
        let mut log = LogViewer::new(100);
        log.push("Hello 世界！");  // Contains wide characters
        // Should not panic or misalign
    }
}
