impl LogViewer {
    /// Set filter pattern (regex or simple text)
    pub fn set_filter(&mut self, pattern: Option<&str>) -> Result<(), regex::Error> {
        self.filter = pattern.map(|p| Regex::new(p)).transpose()?;
        self.update_filtered_view();
        Ok(())
    }

    /// Search for text, returning matching line indices
    pub fn search(&self, query: &str) -> Vec<usize> {
        self.lines.iter()
            .enumerate()
            .filter(|(_, line)| line.raw_content().contains(query))
            .map(|(i, _)| i)
            .collect()
    }

    /// Jump to specific line index
